async (params, browser) => {
  // Open place page
  await browser.open(`${params.place_url}`)

  // Wait for place details
  await browser.waitForSelector('h1, [role=\'main\'] h1', 15000)

  // Let page settle
  await browser.wait(2000)

  // Extract place details
  const place_details = await browser.evaluate(`const nameEl = document.querySelector('h1.DUwDvf, h1'); const ratingEl = document.querySelector('div.F7nice span[aria-hidden="true"], span.ceNzKf, div.jANrlb div.fontDisplayLarge'); const reviewCountEl = document.querySelector('div.F7nice span[aria-label*="review"], button[jsaction*="review"] span'); const addressBtn = document.querySelector('button[data-item-id="address"], button[data-item-id^="address"], button[aria-label*="Address"]'); const phoneBtn = document.querySelector('button[data-item-id^="phone"], a[href^="tel:"], button[aria-label*="Phone"]'); const websiteLink = document.querySelector('a[data-item-id="authority"], a[data-item-id^="authority"], a[aria-label*="Website"]'); const categoryEl = document.querySelector('button[jsaction*="category"], span.DkEaL, .YhemCb'); const hoursEl = document.querySelector('div[aria-label*="hour" i], button[data-item-id="oh"]'); const priceEl = document.querySelector('span[aria-label*="Price"]'); return { name: nameEl ? nameEl.textContent.trim() : 'Unknown', rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', address: addressBtn ? addressBtn.textContent.trim().replace(/^Address:\s*/i, '') : '', phone: phoneBtn ? phoneBtn.textContent.trim().replace(/^Phone:\s*/i, '') : '', website: websiteLink ? websiteLink.href : '', category: categoryEl ? categoryEl.textContent.trim() : '', hours: hoursEl ? hoursEl.getAttribute('aria-label') || hoursEl.textContent.trim() : '', price_level: priceEl ? priceEl.getAttribute('aria-label') || priceEl.textContent.trim() : '', url: window.location.href }`)

  return place_details
}
